function (train_data, test_data, target_variable, num_trees = c(50,      100, 300, 500, 750), interaction_depth = c(5, 6, 10, 15,      20, 30, 40), shrinkage = c(0.1, 0.5, 0.7, 0.9), seed = 123)  {     if (!requireNamespace("gbm", quietly = TRUE)) {         install.packages("gbm")     }     library(gbm)     train_data <- as.data.frame(train_data)     test_data <- as.data.frame(test_data)     if (!(target_variable %in% names(train_data))) {         stop("Target variable not found in training data.")     }     X_train <- train_data[, !(names(train_data) %in% target_variable),          drop = FALSE]     y_train <- train_data[[target_variable]]     X_test <- test_data[, colnames(X_train), drop = FALSE]     X_train <- as.matrix(X_train)     X_test <- as.matrix(X_test)     y_train <- as.numeric(y_train)     formula <- as.formula(paste(target_variable, "~ ."))     best_rmse <- Inf     best_correlation <- -Inf     best_params <- NULL     best_predictions <- NULL     best_model <- NULL     for (trees in num_trees) {         for (depth in interaction_depth) {             for (rate in shrinkage) {                 set.seed(seed)                 gbm_fit <- gbm(formula, data = train_data, distribution = "gaussian",                    n.trees = trees, interaction.depth = depth,                    shrinkage = rate, cv.folds = 5, verbose = FALSE)                 predictions <- predict(gbm_fit, newdata = test_data,                    n.trees = trees)                 predictions_vec <- as.numeric(predictions)                 actual_values <- as.numeric(test_data[[target_variable]])                 rmse <- sqrt(mean((actual_values - predictions_vec)^2))                 correlation <- cor(predictions_vec, actual_values,                    use = "complete.obs")                 if (rmse < best_rmse | (rmse == best_rmse & correlation >                    best_correlation)) {                   best_rmse <- rmse                   best_correlation <- correlation                   best_params <- list(n.trees = trees, interaction.depth = depth,                      shrinkage = rate)                   best_predictions <- predictions_vec                   best_model <- gbm_fit                 }             }         }     }     return(list(predictions = best_predictions, RMSE = best_rmse,          correlation = best_correlation, best_params = best_params,          model = best_model)) }